void removeInterval(pair&lt;int, int&gt; interval) {
    pq.erase(interval);
    leftIntervalMap.erase(interval.first);
    rightIntervalMap.erase(interval.second);
}

int distance(pair&lt;int, int&gt; interval) {
    int x = interval.first;
